#include <stdio.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long N, M;
        scanf("%lld %lld", &N, &M);
        long long ans = 1;
        if (N == 1 && M == 1) {
            printf("2\n");
        } else if (N == 1 || M == 1) {
            printf("2\n");
        } else {
            for (int i = 0; i < (N - 1); i++) {
                ans = (ans * 2) % MOD;
            }
            for (int i = 0; i < (M - 1); i++) {
                ans = (ans * 2) % MOD;
            }
            printf("%lld\n", ans);
        }
    }
    return 0;
}

